interface.pattern:
@Component
class AxonTenantInterceptor(
  private val tenantContext: TenantContext
) : MessageHandlerInterceptor<EventMessage<*>> {

  override fun handle(unitOfWork: UnitOfWork<out EventMessage<*>>, chain: InterceptorChain): Any? {
    val tenantId = unitOfWork.message.metaData["tenant_id"] as? String
    return if (tenantId != null) {
      try {
        tenantContext.setCurrentTenantId(tenantId)
        chain.proceed()
      } finally {
        tenantContext.clearCurrentTenant()
      }
    } else {
      // Log warning for missing tenant_id, continue processing
      chain.proceed()
    }
  }
}

@CommandHandler
constructor(command: CreateWidgetCommand) {
  val tenantId = TenantContext().getCurrentTenantId()
  apply(
    WidgetCreatedEvent(...),
    MetaData.with("tenant_id", tenantId)
  )
}

@EventHandler
fun on(event: WidgetCreatedEvent) {
  val tenantId = TenantContext().getCurrentTenantId() // fail-closed validation
  // Projection update with tenant context for RLS (Layer 3)
  widgetViewRepository.save(WidgetView(..., tenantId))
}

standards.standard:
Use Kotest eventually for async event processing validation.
Pattern: eventually(5.seconds) { projection should have tenant context }
Async processors may have latency, eventually pattern handles timing.
